using TMPro; using UnityEngine; using UnityEngine.UI; using NabyeolDabyeolDreamPuzzle.Agents; using NabyeolDabyeolDreamPuzzle.Puzzle; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.UI { public class HelpOfferController:MonoBehaviour{ [SerializeField] DifficultyAgent difficultyAgent; [SerializeField] BoardManager boardManager; [SerializeField] MoveManager moveManager; [SerializeField] GameObject helpPopup; [SerializeField] TMP_Text messageText; [SerializeField] Button acceptButton,closeButton; DifficultySuggestion currentSuggestion; void Awake(){ difficultyAgent??=FindAnyObjectByType<DifficultyAgent>(); boardManager??=FindAnyObjectByType<BoardManager>(); moveManager??=FindAnyObjectByType<MoveManager>(); HideHelpPopup(); } void OnEnable(){ if(acceptButton)acceptButton.onClick.AddListener(HandleAcceptClicked); if(closeButton)closeButton.onClick.AddListener(HideHelpPopup);} void OnDisable(){ if(acceptButton)acceptButton.onClick.RemoveListener(HandleAcceptClicked); if(closeButton)closeButton.onClick.RemoveListener(HideHelpPopup);} public bool EvaluateAndShowHelp(){ if(difficultyAgent==null) return false; var s=difficultyAgent.EvaluateSuggestion(); if(s.helpType==DifficultyHelpType.None){HideHelpPopup(); return false;} ShowHelpPopup(s); return true;} public void ShowHelpIfAvailable()=>EvaluateAndShowHelp(); public void ShowHintOfferButton()=>ForceShowHintOffer(); public void ShowExtraMoveOfferButton()=>ForceShowExtraMoveOffer(2); public void CloseHelpPopupButton()=>HideHelpPopup(); public void AcceptCurrentHelpButton()=>HandleAcceptClicked(); public void ShowHelpPopup(DifficultySuggestion s){ currentSuggestion=s; if(helpPopup)helpPopup.SetActive(true); if(messageText)messageText.text=string.IsNullOrWhiteSpace(s.message)?"Try a sparkle hint!":s.message; } public void HideHelpPopup(){ if(helpPopup)helpPopup.SetActive(false);} public void ForceShowHintOffer(){ ShowHelpPopup(new DifficultySuggestion{helpType=DifficultyHelpType.ShowHint,message="Try a sparkle hint!",shouldShowHint=true});} public void ForceShowExtraMoveOffer(int n){ ShowHelpPopup(new DifficultySuggestion{helpType=DifficultyHelpType.AddMoves,message="Need a little help? Add extra moves.",extraMoves=Mathf.Max(1,n)});} void HandleAcceptClicked(){ if(currentSuggestion.helpType==DifficultyHelpType.ShowHint&&boardManager)boardManager.LogHint(); else if(currentSuggestion.helpType==DifficultyHelpType.AddMoves&&moveManager)moveManager.AddMoves(Mathf.Max(1,currentSuggestion.extraMoves)); HideHelpPopup(); }} }
